Rule.Source:
import com.six.iam.util.OrionQL;
import com.six.iam.util.TabularData;
import sailpoint.server.Environment;

var hostname = System.getProperty("host.name");
if (hostname != null)
{
    rulerunnerOutput.printNoEscape("<h2>");
    rulerunnerOutput.print(hostname);
    rulerunnerOutput.printNoEscape("</h2>\n");
}

var writer = new TabularData(List.of(
    "key",
    "created=:link(#,${created},${stack:join})",
    "thread=^.threads:get(threadName):link(rulerunner.jsf?rule=six_thread_watcher&amp;title=${@.threadName}&amp;threadSelectorPatterns=${@.threadName:replace( ,\\\\\\\\s)},${@.threadName},${:join})|threadName",
    "context"
), false);
writer.setOutputStream(rulerunnerOutput, "UTF-8");
var connectionSorter = new TreeMap();
for (var connection: Environment.getEnvironment().getSpringDataSource().getConnectionList())
{
    connectionSorter.put(String.format("%s_%d", connection.getCreated(), connectionSorter.size()), connection);
}
var connections = OrionQL.wrap(connectionSorter.values().iterator(), null);
var threads = new HashMap();
for (var threadEntry: Thread.getAllStackTraces().entrySet())
{
    threads.put(threadEntry.getKey().getName(), Arrays.asList(threadEntry.getValue()));
}
connections.implant("threads", threads);
writer.writeHtmlTable(connections);

rulerunnerOutput.addMessage("%d connections listed, %d active connections", writer.getRecordCount(), Environment.getEnvironment().getActiveConnections());
return (threshold != null) && (writer.getRecordCount() > threshold);
